import express, { Express } from 'express';
import cors from 'cors';
import helmet from 'helmet';
import morgan from 'morgan';
import apiRouter from './routes/index.js';
import {errorMiddleware} from "./middlewares/error.middleware";

const app: Express = express();

app.use(helmet());
app.use(cors());
app.use(morgan('dev'));
app.use(express.json());

app.use('/api', apiRouter);
app.use(errorMiddleware);

export default app;

import express, { Express, Router } from 'express';
import cors from 'cors';
import helmet from 'helmet';
import morgan from 'morgan';
import { errorMiddleware } from './middlewares/error.middleware.js';

const app: Express = express();

app.use(helmet());
app.use(cors());
app.use(morgan('dev'));
app.use(express.json());

// Routes are mounted after async bootstrap (see server.ts)
export function mountRouter(router: Router): void {
    app.use('/api', router);
    app.use(errorMiddleware);
}

export default app;

import { Router } from 'express';
import { getHealth } from '../controllers/health.controller.js';

const router = Router();

router.get('/', (_req, res) => {
    res.json({ message: 'API root' });
});

router.get('/health', getHealth);

export default router;

import { Router } from 'express';
import { getHealth } from '../controllers/health.controller.js';
import { createAuthRouter } from '../modules/auth/auth.routes.js';

export async function createApiRouter(): Promise<Router> {
    const router = Router();

    router.get('/', (_req, res) => {
        res.json({ message: 'API root' });
    });

    router.get('/health', getHealth);

    // Auth — all routes mounted at /api/auth
    const authRouter = await createAuthRouter();
    router.use('/auth', authRouter);

    return router;
}

import 'dotenv/config';
import app from './app.js';
import { env } from './config/env.js';
import { connectToDatabase } from './config/database.js';

async function bootstrap(): Promise<void> {
    try {
        await connectToDatabase();
        console.log('Database connected successfully');

        app.listen(env.port, () => {
            console.log(`Server running on http://localhost:${env.port}`);
        });
    } catch (error) {
        console.error('Failed to start server', error);
        process.exit(1);
    }
}

void bootstrap();

import 'dotenv/config';
import app, { mountRouter } from './app.js';
import { env } from './config/env.js';
import { connectToDatabase } from './config/database.js';
import { createApiRouter } from './routes/index.js';

async function bootstrap(): Promise<void> {
    try {
        await connectToDatabase();
        console.log('Database connected successfully');

        const apiRouter = await createApiRouter();
        mountRouter(apiRouter);

        app.listen(env.port, () => {
            console.log(`Server running on http://localhost:${env.port}`);
        });
    } catch (error) {
        console.error('Failed to start server', error);
        process.exit(1);
    }
}

void bootstrap();
